class Vehicle {
  String brand = "Naməlum";

  void move() {
    System.out.println(brand + " hərəkət edir.");
  }
}

class Car extends Vehicle {
  String model = "Sedan";

  void display() {
    System.out.println("Marka: " + brand + ", Model: " + model);
  }
}

public class Main {
  public static void main(String[] args) {
    Car car = new Car();
    car.move();
    car.display();
  }
}
// Çıxış:
// Naməlum hərəkət edir.
// Marka: Naməlum, Model: Sedan

class Animal {
  protected String name = "Bilinmir";

  protected void makeSound() {
    System.out.println(name + " səs çıxarır.");
  }
}

class Dog extends Animal {
  void setName(String name) {
    this.name = name;
  }

  void bark() {
    System.out.println(name + " havlayır.");
  }
}

public class Main {
  public static void main(String[] args) {
    Dog dog = new Dog();
    dog.setName("Rex");
    dog.makeSound();
    dog.bark();
  }
}
// Çıxış:
// Rex səs çıxarır.
// Rex havlayır.

