class Person {
  String name;

  Person(String name) {
    this.name = name;
  }

  void introduce() {
    System.out.println("Adım: " + name);
  }
}

class Student extends Person {
  int grade;

  Student(String name, int grade) {
    super(name);
    this.grade = grade;
  }

  @Override
  void introduce() {
    super.introduce();
    System.out.println("Sinf: " + grade);
